export type BaseFieldProps = {
  id: string;
  label: string;
  error?: string;
};

export type TextInputProps = BaseFieldProps & {
  value: string;
  onChange: (value: string) => void;
  type?: 'text' | 'email';
};

// Generic helper — optional stretch
export type SelectOption<T extends string> = {
  value: T;
  label: string;
};

type ButtonProps = {
  isLoading?: boolean;
  disabled?: boolean;
  children: React.ReactNode;
  onClick?: () => void;
};

export function Button({ isLoading, disabled, children, onClick }: ButtonProps) {
  return (
    <button type="button" disabled={disabled || isLoading} onClick={onClick}>
      {isLoading ? 'Loading…' : children}
    </button>
  );
}

